{
  "decision": "Reject q8_0/tbq4; adopt q4_0/q4_0",
  "evidence": "LLM recommendation states q8_0/tbq4 offers no performance benefit over q4_0 on CPU-only ARM64, while q4_0/q4_0 provides better memory reduction and addresses the 2.5s latency bottleneck without sacrificing safety-critical confidence thresholds.",
  "caveats": "q8_0/tbq4 is described as 'quality-preserving' but not 'strict lossless'; the CPU-only constraint makes high-precision formats too memory-intensive and slow for the 8K context requirement.",
  "next_action": "Deploy q4_0/q4_0 configuration and monitor KV memory usage and step latency against the 2.5s budget."
}
